patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..1a51200777f9 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2227,6 +2227,21 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
               matchBSwapOrBitReverse(*II, /*MatchBSwaps*/ true,
                                      /*MatchBitReversals*/ true))
         return BitOp;
+
+    }
+    
+    // fshl(X, 0, Y) --> shl X, (Y & (BitWidth-1)) if BitWidth is power-of-2.
+    // fshl(X, undef, Y) --> shl X, (Y & (BitWidth-1)) if BitWidth is power-of-2.
+    // If Y is known to be less than BitWidth, the mask is not needed.
+    if (IID == Intrinsic::fshl &&
+        (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
+      KnownBits Op2Known = computeKnownBits(II->getArgOperand(2), 0, II);
+      Value *ShAmt = II->getArgOperand(2);
+      if (Op2Known.getMaxValue().ult(BitWidth))
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+      if (isPowerOf2_32(BitWidth))
+        return BinaryOperator::CreateShl(Op0,
+            Builder.CreateAnd(ShAmt, ConstantInt::get(Ty, BitWidth - 1)));
     }

     // Left or right might be masked.

